SELECT ?lifespan WHERE {
  ?item wdt:P4214 ?lifespan .
  ?item wdt:P4743 wd:Q3947 .
  {
    SELECT ?item (MAX(?age) AS ?maxAge)
    WHERE {
      ?item wdt:P4214 ?age .
      ?item wdt:P4743 wd:Q3947 .
    }
    GROUP BY ?item
  }
  {
    SELECT ?item2 (MAX(?age2) AS ?maxAge2)
    WHERE {
      ?item2 wdt:P4214 ?age2 .
      ?item2 wdt:P4743 wd:Q3947 .
    }
    GROUP BY ?item2
  }
  FILTER NOT EXISTS {
    ?item wdt:P4214 ?maxAge .
  }
  FILTER (?lifespan < ?maxAge)
  FILTER EXISTS {
    ?item wdt:P4214 ?lifespan2 .
    FILTER (?lifespan2 > ?lifespan)
  }
  FILTER (?lifespan = (MAX(?lifespan)))
} LIMIT 1

