  {
    wd:Q117188122 wdt:P361 ?galapagosIsland .
    ?galapagosIsland wdt:P31 wd:Q23442 .
    BIND(wd:Q117188122 AS ?archipelago)
  } UNION {
    wd:Q43594 wdt:P361 ?hawaiianIsland .
    ?hawaiianIsland wdt:P31 wd:Q23442 .
    BIND(wd:Q43594 AS ?archipelago)
  }
  BIND(?archipelago AS ?archipelagoVar)
  ?archipelagoVar rdfs:label ?archipelagoLabel .
  FILTER(LANGMATCHES(LANG(?archipelagoLabel), "en"))
}
GROUP BY ?archipelago ?archipelagoLabel
ORDER BY DESC(?islandCount)

